import{_ as e,c as s,o as i,a8 as n}from"./chunks/framework.BrmF0WDH.js";const u=JSON.parse('{"title":"00-新人30分钟了解项目精髓","description":"","frontmatter":{},"headers":[],"relativePath":"onboarding/00-新人30分钟了解项目精髓/index.md","filePath":"onboarding/00-新人30分钟了解项目精髓/index.md","lastUpdated":1777649372000}'),o={name:"onboarding/00-新人30分钟了解项目精髓/index.md"};function l(d,a,t,c,p,r){return i(),s("div",null,a[0]||(a[0]=[n(`<h1 id="_00-新人30分钟了解项目精髓" tabindex="1">00-新人30分钟了解项目精髓 <a class="header-anchor" href="#_00-新人30分钟了解项目精髓" aria-label="Permalink to &quot;00-新人30分钟了解项目精髓&quot;">​</a></h1><h2 id="一句话理解项目" tabindex="1">一句话理解项目 <a class="header-anchor" href="#一句话理解项目" aria-label="Permalink to &quot;一句话理解项目&quot;">​</a></h2><p>这是一个把页面结构存成 <code>Schema</code>，再通过 <code>Core + Runtime</code> 执行出来，同时让 <code>Editor + Sandbox</code> 提供可视化编辑体验的低代码引擎。</p><h2 id="先记住-4-个判断" tabindex="1">先记住 4 个判断 <a class="header-anchor" href="#先记住-4-个判断" aria-label="Permalink to &quot;先记住 4 个判断&quot;">​</a></h2><h3 id="_1-schema-是单一事实来源" tabindex="1">1. <code>Schema</code> 是单一事实来源 <a class="header-anchor" href="#_1-schema-是单一事实来源" aria-label="Permalink to &quot;1. \`Schema\` 是单一事实来源&quot;">​</a></h3><p>编辑器里你看到的树、属性面板里的值、运行时渲染出的页面，本质都来自同一份 <code>ISchemasRoot</code>。</p><p>新人只要抓住这一点，很多问题都会简单很多：</p><ul><li>为什么改属性会刷新画布</li><li>为什么切页只是在切 <code>page.field</code></li><li>为什么复制粘贴本质上是在复制节点配置</li></ul><h3 id="_2-editor-不负责渲染业务组件" tabindex="1">2. <code>Editor</code> 不负责渲染业务组件 <a class="header-anchor" href="#_2-editor-不负责渲染业务组件" aria-label="Permalink to &quot;2. \`Editor\` 不负责渲染业务组件&quot;">​</a></h3><p><code>packages/editor</code> 维护的是编辑态状态和操作能力，例如：</p><ul><li>当前选中了谁</li><li>往哪个父节点里加新节点</li><li>历史记录怎么回退</li><li>属性变化后如何同步给画布</li></ul><p>真正的页面渲染发生在 iframe 里的 runtime，而不是编辑器自己。</p><h3 id="_3-sandbox-不是运行时-它只是编辑桥" tabindex="1">3. <code>Sandbox</code> 不是运行时，它只是编辑桥 <a class="header-anchor" href="#_3-sandbox-不是运行时-它只是编辑桥" aria-label="Permalink to &quot;3. \`Sandbox\` 不是运行时，它只是编辑桥&quot;">​</a></h3><p><code>packages/sandbox</code> 的职责非常纯粹：</p><ul><li>用 <code>iframe</code> 托起一个隔离运行环境</li><li>把编辑器里的“增删改查、选中、高亮、拖拽缩放”映射到 iframe 页面</li><li>反过来把 iframe 内页面尺寸、元素位置、选中元素反馈给编辑器</li></ul><p>所以它更像“编辑态控制层”，不是业务渲染层。</p><h3 id="_4-core-才是执行引擎" tabindex="1">4. <code>Core</code> 才是执行引擎 <a class="header-anchor" href="#_4-core-才是执行引擎" aria-label="Permalink to &quot;4. \`Core\` 才是执行引擎&quot;">​</a></h3><p><code>packages/core</code> 里的 <code>LowCodeRoot / LowCodePage / LowCodeNode</code> 负责：</p><ul><li>建立页面节点树</li><li>编译模板表达式，例如 <code>\${user.name}</code></li><li>绑定生命周期和事件</li><li>收集数据源依赖</li><li>在数据变化时重新计算节点数据和显示条件</li></ul><p>如果把项目类比成前端框架，<code>Core</code> 更接近运行时内核。</p><h2 id="_30-分钟阅读路径" tabindex="1">30 分钟阅读路径 <a class="header-anchor" href="#_30-分钟阅读路径" aria-label="Permalink to &quot;30 分钟阅读路径&quot;">​</a></h2><h3 id="第-1-步-看项目骨架" tabindex="1">第 1 步：看项目骨架 <a class="header-anchor" href="#第-1-步-看项目骨架" aria-label="Permalink to &quot;第 1 步：看项目骨架&quot;">​</a></h3><p>重点目录：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>apps/</span></span>
<span class="line"><span>  playground/        编辑器演示应用</span></span>
<span class="line"><span>  quantum-docs/      文档站</span></span>
<span class="line"><span>packages/</span></span>
<span class="line"><span>  core/              页面执行内核</span></span>
<span class="line"><span>  editor/            编辑器状态和界面</span></span>
<span class="line"><span>  sandbox/           iframe 画布桥接层</span></span>
<span class="line"><span>  data-source/       数据源与依赖触发</span></span>
<span class="line"><span>  ui/                Vue3 运行时组件库</span></span>
<span class="line"><span>  ui-vue2/           Vue2 运行时组件库</span></span>
<span class="line"><span>  schemas/           Schema 类型协议</span></span>
<span class="line"><span>  utils/             通用工具</span></span>
<span class="line"><span>runtime/</span></span>
<span class="line"><span>  vue3-active/       Vue3 runtime</span></span>
<span class="line"><span>  vue2-active/       Vue2 runtime</span></span></code></pre></div><h3 id="第-2-步-看真正的主链路" tabindex="1">第 2 步：看真正的主链路 <a class="header-anchor" href="#第-2-步-看真正的主链路" aria-label="Permalink to &quot;第 2 步：看真正的主链路&quot;">​</a></h3><p>主链路只有一条：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[编辑器修改 Schema] --&gt; B[EditorService 更新 root]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[Sandbox 调 runtime.updateRootConfig]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[LowCodeRoot / LowCodePage / LowCodeNode 重建或更新]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[UI 组件按 config 渲染]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[页面展示]</span></span></code></pre></div><p>数据源主链路是另一条：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[DataSource.setData] --&gt; B[DataSourceManager change]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[trigger 依赖]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[LowCodeNode.setData / compileCond]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[runtime 页面节点被替换]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[Vue 组件重新渲染]</span></span></code></pre></div><h3 id="第-3-步-记住几个关键文件" tabindex="1">第 3 步：记住几个关键文件 <a class="header-anchor" href="#第-3-步-记住几个关键文件" aria-label="Permalink to &quot;第 3 步：记住几个关键文件&quot;">​</a></h3><ul><li><code>packages/core/src/app.ts</code><ul><li>入口根实例，负责 <code>setConfig</code>、<code>setPage</code>、事件注册、组件注册</li></ul></li><li><code>packages/core/src/node.ts</code><ul><li>节点编译中心，模板表达式、条件显示、生命周期、事件包装都在这里</li></ul></li><li><code>packages/data-source/src/utils/deps.ts</code><ul><li>数据依赖收集和触发的核心实现</li></ul></li><li><code>packages/editor/src/services/editor-service.ts</code><ul><li>编辑器最重要的状态流入口</li></ul></li><li><code>packages/sandbox/src/box-render.ts</code><ul><li>iframe 通信和 runtime 接口桥接</li></ul></li><li><code>runtime/vue3-active/playground/App.vue</code><ul><li>编辑态 runtime 对外暴露 <code>updateRootConfig / select / add / update / delete</code></li></ul></li><li><code>packages/ui/src/q-component/src/component.vue</code><ul><li>动态组件渲染入口</li></ul></li></ul><h2 id="新人最容易误解的点" tabindex="1">新人最容易误解的点 <a class="header-anchor" href="#新人最容易误解的点" aria-label="Permalink to &quot;新人最容易误解的点&quot;">​</a></h2><h3 id="_1-不是-拖拽驱动渲染-而是-schema-驱动渲染" tabindex="1">1. 不是“拖拽驱动渲染”，而是“Schema 驱动渲染” <a class="header-anchor" href="#_1-不是-拖拽驱动渲染-而是-schema-驱动渲染" aria-label="Permalink to &quot;1. 不是“拖拽驱动渲染”，而是“Schema 驱动渲染”&quot;">​</a></h3><p>拖拽只是修改 Schema 的一种手段。</p><h3 id="_2-不是-编辑器直接操作-dom-而是-编辑器改-schema-sandbox-同步-iframe" tabindex="1">2. 不是“编辑器直接操作 DOM”，而是“编辑器改 Schema，Sandbox 同步 iframe” <a class="header-anchor" href="#_2-不是-编辑器直接操作-dom-而是-编辑器改-schema-sandbox-同步-iframe" aria-label="Permalink to &quot;2. 不是“编辑器直接操作 DOM”，而是“编辑器改 Schema，Sandbox 同步 iframe”&quot;">​</a></h3><p>DOM 操作主要发生在选中、高亮、拖拽蒙层和 Moveable 控制器层面，不是页面内容的真源头。</p><h3 id="_3-不是-数据源直接驱动-vue-组件-而是-数据源先驱动-lowcodenode-再驱动页面配置" tabindex="1">3. 不是“数据源直接驱动 Vue 组件”，而是“数据源先驱动 LowCodeNode，再驱动页面配置” <a class="header-anchor" href="#_3-不是-数据源直接驱动-vue-组件-而是-数据源先驱动-lowcodenode-再驱动页面配置" aria-label="Permalink to &quot;3. 不是“数据源直接驱动 Vue 组件”，而是“数据源先驱动 LowCodeNode，再驱动页面配置”&quot;">​</a></h3><p>这个中间层很关键，它决定了：</p><ul><li>模板表达式如何重算</li><li><code>ifShow</code> 如何重算</li><li>生命周期与事件如何继续成立</li></ul><h2 id="新人上手时最有价值的调试顺序" tabindex="1">新人上手时最有价值的调试顺序 <a class="header-anchor" href="#新人上手时最有价值的调试顺序" aria-label="Permalink to &quot;新人上手时最有价值的调试顺序&quot;">​</a></h2><p>当你发现“改了没生效”，按这个顺序查：</p><ol><li><code>root</code> 里的 Schema 是否已经变了</li><li>runtime 是否收到了 <code>updateRootConfig</code> / <code>update</code></li><li><code>LowCodeNode.setData</code> 是否被执行</li><li><code>componentProps</code> / <code>style</code> 是否已经变成最终值</li><li>UI 组件是否真的消费了这些值</li></ol><h2 id="一句话收尾" tabindex="1">一句话收尾 <a class="header-anchor" href="#一句话收尾" aria-label="Permalink to &quot;一句话收尾&quot;">​</a></h2><p>想快速上手这个项目，不要先盯界面，先盯 <code>Schema -&gt; Core -&gt; Runtime</code> 这条线；界面只是这条线在编辑态的投影。</p>`,44)]))}const m=e(o,[["render",l]]);export{u as __pageData,m as default};
